+            "dup-corr".into(),
+            MissionActorRole::Operator,
+            "first".into(),
+            None,
+            1000,
+        )
+        .unwrap();
+
+    let result = journal.append(
+        MissionJournalEntryKind::ControlCommand {
+            command: "resume".into(),
+        },
+        "dup-corr".into(),
+        MissionActorRole::Operator,
+        "second".into(),
+        None,
+        2000,
